import{_ as e,c as a,o as t,a4 as r}from"./chunks/framework.HaEZziQ1.js";const u=JSON.parse('{"title":"FFmpeg播放器开发","description":"","frontmatter":{},"headers":[],"relativePath":"Document/基于FFmpeg的使用和开发/6.FFmpeg播放器开发.md","filePath":"Document/基于FFmpeg的使用和开发/6.FFmpeg播放器开发.md","lastUpdated":1709668918000}'),l={name:"Document/基于FFmpeg的使用和开发/6.FFmpeg播放器开发.md"},o=r('<h1 id="ffmpeg播放器开发" tabindex="-1">FFmpeg播放器开发 <a class="header-anchor" href="#ffmpeg播放器开发" aria-label="Permalink to &quot;FFmpeg播放器开发&quot;">​</a></h1><h2 id="libvlc库" tabindex="-1">libVLC库 <a class="header-anchor" href="#libvlc库" aria-label="Permalink to &quot;libVLC库&quot;">​</a></h2><p>官网：<a href="https://www.videolan.org/" target="_blank" rel="noreferrer">VLC：官方网站 - 全平台的自由多媒体解决方案！ - VideoLAN</a></p><p>开源地址：<a href="https://github.com/videolan/vlc" target="_blank" rel="noreferrer">https://github.com/videolan/vlc</a></p><p>[VLC Media Player_百度百科 (baidu.com)](<a href="https://baike.baidu.com/item/VLC" target="_blank" rel="noreferrer">https://baike.baidu.com/item/VLC</a> Media Player/7393175)</p><p>VLC Media Player（VLC多媒体播放器），最初命名为VideoLAN客户端，是VideoLAN品牌产品，是VideoLAN计划的多媒体播放器。它支持众多音频与视频解码器及文件格式，并支持DVD影音光盘，VCD影音光盘及各类流式协议。</p><p>它也能作为<a href="https://baike.baidu.com/item/unicast/10769943?fromModule=lemma_inlink" target="_blank" rel="noreferrer">unicast</a>或multicast的流式服务器在IPv4或<a href="https://baike.baidu.com/item/IPv6/172297?fromModule=lemma_inlink" target="_blank" rel="noreferrer">IPv6</a>的高速网络连接下使用。它融合了FFmpeg计划的解码器与libdvdcss程序库使其有播放多媒体文件及加密DVD影碟的功能。</p><p>VLC媒体播放器是一款非常实用、功能丰富、跨平台的媒体播放器，它能够轻松处理各种媒体文件，并且易于使用。</p><h2 id="mencoder" tabindex="-1">mencoder <a class="header-anchor" href="#mencoder" aria-label="Permalink to &quot;mencoder&quot;">​</a></h2><p><a href="https://baike.baidu.com/item/mencoder/9960724" target="_blank" rel="noreferrer">mencoder_百度百科 (baidu.com)</a></p><p>mencoder 是一款命令行方式的视频处理软件，是Mplayer自带的编码工具 (Mplayer是Linux下的播放器，开源，支持几乎所有视频格式的播放，有windows和Mac版本)</p><p>mencoder支持几乎所有的格式的视频转换，可以将任意格式转换到任意格式，转换功能可以说是相当强大。市面上流行的格式转换器，都是基于mencoder开发的GUl，比如暴风转码，格式工厂等。</p><p>可以说转换器能办到的，mencoder都能办到，但mencoder能办到的，转换器就不一定能办到了</p><p>很多初学者宁可去用转换器，也不用mencoder的很大原因是mencoder只支持在命令行下操作.</p><p><a href="https://baike.baidu.com/item/Mplayer" target="_blank" rel="noreferrer">Mplayer_百度百科 (baidu.com)</a></p><h2 id="基于ffmpeg-sdl的音频视频编码播放器的开发" tabindex="-1">基于FFmpeg+SDL的音频视频编码播放器的开发 <a class="header-anchor" href="#基于ffmpeg-sdl的音频视频编码播放器的开发" aria-label="Permalink to &quot;基于FFmpeg+SDL的音频视频编码播放器的开发&quot;">​</a></h2><p>雷霄骅大佬</p><h3 id="视频播放器原理" tabindex="-1">视频播放器原理 <a class="header-anchor" href="#视频播放器原理" aria-label="Permalink to &quot;视频播放器原理&quot;">​</a></h3><p>播放一个视频文件的流程如下所示</p><h4 id="常用播放器" tabindex="-1">常用播放器 <a class="header-anchor" href="#常用播放器" aria-label="Permalink to &quot;常用播放器&quot;">​</a></h4><p>跨平台系列（非DirectShow框架）</p><p>VLC，Mplayer，ffplay……</p><p>Windows系列（ DirectShow框架）</p><p>完美解码，终极解码，暴风影音……</p><h4 id="信息查看工具" tabindex="-1">信息查看工具 <a class="header-anchor" href="#信息查看工具" aria-label="Permalink to &quot;信息查看工具&quot;">​</a></h4><p>综合信息查看：MediaInfo</p><p>二进制信息查看：UltraEdit</p><p>单项详细分析</p><ul><li> 封装格式：Elecard Format Analyzer</li><li> 视频编码数据：Elecard Stream Eye</li><li> 视频像素数据：YUV Player</li><li> 音频采样数据：Adobe Audition</li></ul><h4 id="封装格式" tabindex="-1">封装格式 <a class="header-anchor" href="#封装格式" aria-label="Permalink to &quot;封装格式&quot;">​</a></h4><p>封装格式的作用：视频码流和音频码流按照一定的格式存储在一个文件中。</p><p>封装格式分析工具：Elecard Format Analyzer</p><table><thead><tr><th>名称</th><th>推出机构</th><th>目前使用领域</th></tr></thead><tbody><tr><td>AVI</td><td>Microsoft Inc.</td><td>BT下载影视</td></tr><tr><td>MP4</td><td>MPEG</td><td>互联网视频网站</td></tr><tr><td>TS</td><td>MPEG</td><td>IPTV，数字电视</td></tr><tr><td>FLV</td><td>Adobe Inc</td><td>互联网视频网站</td></tr><tr><td>MKV</td><td>CoreCodec Inc.</td><td>互联网视频网站</td></tr><tr><td>RMVB</td><td>Real Networks Inc.</td><td>BT下载影视</td></tr></tbody></table><h4 id="视频编码数据" tabindex="-1">视频编码数据 <a class="header-anchor" href="#视频编码数据" aria-label="Permalink to &quot;视频编码数据&quot;">​</a></h4><p>视频编码的作用：将视频像素数据（RGB，YUV等）压缩成为视频码流，从而降低视频的数据量。</p><p>视频编码分析工具：Elecard Stream Eye</p><h4 id="音频编码数据" tabindex="-1">音频编码数据 <a class="header-anchor" href="#音频编码数据" aria-label="Permalink to &quot;音频编码数据&quot;">​</a></h4><p>音频编码的作用：将音频采样数据（PCM等）压缩成为音频码流，从而降低音频的数据量。</p><p>音频编码分析工具：暂不涉及</p><h4 id="视频像素数据" tabindex="-1">视频像素数据 <a class="header-anchor" href="#视频像素数据" aria-label="Permalink to &quot;视频像素数据&quot;">​</a></h4><p>视频像素数据作用：保存了屏幕上每个像素点的像素值。</p><h5 id="格式" tabindex="-1">格式 <a class="header-anchor" href="#格式" aria-label="Permalink to &quot;格式&quot;">​</a></h5><p>常见的像素数据格式有RGB24， RGB32， YUV420P，YUV422P，YUV444P等。压缩编码中一般使用的是YUV格式的像素数据，最为常见的格式为YUV420P。</p><h5 id="特点" tabindex="-1">特点 <a class="header-anchor" href="#特点" aria-label="Permalink to &quot;特点&quot;">​</a></h5><p>视频像素数据体积很大，一般情况下1小时高清视频的RGB24</p><p>格式的数据体积为：3600<em>25</em>1920<em>1080</em>3=559.9GByte</p><p>PS:这里假定帧率为25Hz,取样精度8bit。</p><h5 id="yuv格式像素数据查看工具" tabindex="-1">YUV格式像素数据查看工具 <a class="header-anchor" href="#yuv格式像素数据查看工具" aria-label="Permalink to &quot;YUV格式像素数据查看工具&quot;">​</a></h5><p>YUV Player：<a href="https://github.com/latelee/YUVPlayer" target="_blank" rel="noreferrer">https://github.com/latelee/YUVPlayer</a></p><p>RGB格式简介</p><ul><li>Red、Green、Blue三种颜色，可以混合成世界上所有的颜色。</li><li>彩色图像中每个点，由R、G、B三个分量组成</li></ul><h6 id="yuv格式简介" tabindex="-1">YUV格式简介 <a class="header-anchor" href="#yuv格式简介" aria-label="Permalink to &quot;YUV格式简介&quot;">​</a></h6><p>相关实验表明，人眼对亮度敏感而对色度不敏感。因而可以将亮度信息和色度信息分离，并对色度信息采用更“狠”一点的压缩方案，从而提高压缩效率。</p><h4 id="音频采样数据" tabindex="-1">音频采样数据 <a class="header-anchor" href="#音频采样数据" aria-label="Permalink to &quot;音频采样数据&quot;">​</a></h4><p><strong>音频采样数据作用</strong>：保存了音频中每个采样点的值。</p><p><strong>特点</strong>：音频采样数据体积很大，一般情况下一首4分钟的PCM格式的</p><p><strong>歌曲体积为</strong>：4<em>60</em>44100<em>2</em>2=42.3MByte</p><p>PS:这里假定采样率为44100Hz，采样精度为16bit。</p><p><strong>音频采样数据查看工具</strong>：Adobe Audition</p><p><strong>PCM格式简介</strong></p><ul><li>单声道的情况下按照顺序存储每个采样点的数据。</li><li>双声道的情况下按照“左右、左右”的顺序存储每个采样点两个声道的数据。</li></ul><h3 id="ffmpeg视频解码器" tabindex="-1">FFmpeg视频解码器 <a class="header-anchor" href="#ffmpeg视频解码器" aria-label="Permalink to &quot;FFmpeg视频解码器&quot;">​</a></h3><h3 id="sdl视频显示" tabindex="-1">SDL视频显示 <a class="header-anchor" href="#sdl视频显示" aria-label="Permalink to &quot;SDL视频显示&quot;">​</a></h3><h3 id="ffmpeg-sdl视频播放器" tabindex="-1">FFmpeg+SDL视频播放器 <a class="header-anchor" href="#ffmpeg-sdl视频播放器" aria-label="Permalink to &quot;FFmpeg+SDL视频播放器&quot;">​</a></h3><h3 id="ffmpeg-sdl视频播放器-图形界面版" tabindex="-1">FFmpeg+SDL视频播放器-图形界面版 <a class="header-anchor" href="#ffmpeg-sdl视频播放器-图形界面版" aria-label="Permalink to &quot;FFmpeg+SDL视频播放器-图形界面版&quot;">​</a></h3>',65),d=[o];function i(n,p,h,m,c,s){return t(),a("div",null,d)}const f=e(l,[["render",i]]);export{u as __pageData,f as default};
